def encode(message):
    vowels = 'aeiouAEIOU'
    encoded_message = ''
    for char in message:
        if char in vowels:
            index = (vowels.index(char) + 2) % 26
            encoded_message += chr(ord('a') + index)
        else:
            encoded_message += char
    return encoded_message
